def find_max(numbers):
    maximum = numbers[0]
    for number in numbers:
        if number > maximum:
            maximum = number
    return maximum

def count_vowels(text):
    vowels = "aeiou"
    count = 0
    for char in text.lower():
        if char in vowels:
            count += 1
    return count

def factorial(n):
    result = 1
    for i in range(1, n + 1):
        result *= i
    return result

def calculate_average(numbers):
    if not numbers:
        return 0
    return sum(numbers) / len(numbers)

def is_palindrome(text):
    cleaned = text.replace(" ", "").lower()
    return cleaned == cleaned[::-1]

def count_words(sentence):
    words = sentence.split()
    return len(words)

def find_min(numbers):
    minimum = numbers[0]
    for number in numbers:
        if number < minimum:
            minimum = number
    return minimum

def multiply_numbers(numbers):
    result = 1
    for number in numbers:
        result *= number
    return result

def remove_duplicates(items):
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def flatten_list(nested_list):
    result = []
    for sublist in nested_list:
        result.extend(sublist)
    return result

def find_index(items, target):
    for index, value in enumerate(items):
        if value == target:
            return index
    return -1

def divide_numbers(a, b):
    if b == 0:
        return None
    return a / b

def evaluate_score(score):
    if score >= 50:
        if score >= 70:
            if score >= 90:
                return "Excellent"
            else:
                return "Very Good"
        else:
            return "Pass"
    else:
        return "Fail"

def categorize_age(age):
    if age > 0:
        if age < 18:
            if age < 13:
                return "Child"
            else:
                return "Teen"
        else:
            if age < 60:
                return "Adult"
            else:
                return "Senior"

def check_triangle(a, b, c):
